CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`rights`.`event_blackout_rule` (
    `event_blackout_rule_id` BIGINT COMMENT 'Primary key for event blackout rule',
    `rights_territory_id` BIGINT COMMENT 'Additional FK to rights territory for multi-territory rules',
    `event_rights_territory_id` BIGINT COMMENT 'FK to rights territory for geographic scope',
    `license_agreement_id` BIGINT COMMENT 'FK to the license agreement governing this blackout',
    `sports_event_id` BIGINT COMMENT 'FK to the sports event subject to blackout',
    `rights_blackout_rule_id` BIGINT COMMENT 'FK to the parent rights blackout rule being extended',
    `_created_at` TIMESTAMP COMMENT 'Lineage: record creation timestamp',
    `_source_code` STRING COMMENT 'Lineage: identifier in source system',
    `_updated_at` TIMESTAMP COMMENT 'Lineage: record last update timestamp',
    `applies_to_linear_flag` BOOLEAN COMMENT 'Whether the blackout applies to linear broadcast',
    `applies_to_ott_flag` BOOLEAN COMMENT 'Whether the blackout applies to OTT/streaming platforms',
    `applies_to_platform` STRING COMMENT 'Platform(s) to which the blackout applies',
    `blackout_end_at` TIMESTAMP COMMENT 'Timestamp when the blackout window ends',
    `blackout_end_timestamp` TIMESTAMP COMMENT 'Alternative end timestamp for blackout window',
    `blackout_name` STRING COMMENT 'Descriptive name for the blackout rule',
    `blackout_reason` STRING COMMENT 'Business reason for the blackout (e.g. league mandate, contractual)',
    `blackout_scope` STRING COMMENT 'Scope of the blackout (full, partial, delayed)',
    `blackout_start_at` TIMESTAMP COMMENT 'Timestamp when the blackout window begins',
    `blackout_start_timestamp` TIMESTAMP COMMENT 'Alternative start timestamp for blackout window',
    `blackout_status` STRING COMMENT 'Operational status of the blackout (pending, active, lifted, expired)',
    `blackout_type` STRING COMMENT 'Type of blackout (e.g. home-market, national, regional)',
    `country_code` STRING COMMENT 'ISO country code where blackout applies',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp',
    `dma_code` STRING COMMENT 'Designated Market Area code for the blackout region',
    `dma_name` STRING COMMENT 'Human-readable name of the DMA',
    `home_market_protection_flag` BOOLEAN COMMENT 'Whether this protects the home market broadcast rights',
    `is_active_flag` BOOLEAN COMMENT 'Whether this blackout rule is currently active',
    `league_mandated_flag` BOOLEAN COMMENT 'Whether the blackout is mandated by the sports league',
    `lift_condition` STRING COMMENT 'Condition under which the blackout may be lifted (e.g. sellout)',
    `override_allowed_flag` BOOLEAN COMMENT 'Whether the blackout can be overridden by operator',
    `radius_miles` DECIMAL(18,2) COMMENT 'Geographic radius in miles for the blackout zone',
    `region_scope` STRING COMMENT 'Scope of the region (local, regional, national)',
    `source_code` STRING COMMENT 'Identifier in the source system',
    `event_blackout_rule_status` STRING COMMENT 'Current status of the blackout rule',
    `territory_code` STRING COMMENT 'Territory/country code where blackout applies',
    `updated_at` TIMESTAMP COMMENT 'Record last update timestamp',
    CONSTRAINT pk_event_blackout_rule PRIMARY KEY(`event_blackout_rule_id`)
) COMMENT 'DMA/territory blackout rule for sports events, extending rights_blackout_rule with geographic and platform-specific blackout enforcement for live sports broadcasting rights.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`rights`.`pro_affiliation` (
    `pro_affiliation_id` BIGINT COMMENT 'Surrogate primary key for the PRO affiliation.',
    `holder_id` BIGINT COMMENT 'FK to the rights holder affiliated with the PRO.',
    `_source_code` STRING COMMENT 'Source record identifier for medallion lineage.',
    `active_flag` BOOLEAN COMMENT 'Whether the PRO affiliation is currently active.',
    `affiliated_party_name` STRING COMMENT 'Name of the affiliated writer/publisher.',
    `affiliation_end_date` DATE COMMENT 'Date affiliation with the PRO ended, if any.',
    `affiliation_start_date` DATE COMMENT 'Date affiliation with the PRO began.',
    `collection_share_percent` DECIMAL(18,2) COMMENT 'Performance royalty collection share.',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp.',
    `effective_date` DATE COMMENT 'Affiliation effective date.',
    `member_ipi_number` STRING COMMENT 'Member IPI/CAE number registered with the PRO.',
    `membership_role` STRING COMMENT 'Role at the PRO (writer, publisher, both).',
    `pro_code` STRING COMMENT 'Short code identifying the PRO.',
    `pro_name` STRING COMMENT 'Performance Rights Organization name (ASCAP/BMI/SESAC/PRS).',
    `royalty_routing_account` STRING COMMENT 'Account used to route performance royalties from the PRO.',
    `source_code` STRING COMMENT 'Natural key in the source system.',
    `termination_date` DATE COMMENT 'Affiliation termination date.',
    `territory` STRING COMMENT 'Territory covered by the PRO.',
    `updated_at` TIMESTAMP COMMENT 'Record last update timestamp.',
    CONSTRAINT pk_pro_affiliation PRIMARY KEY(`pro_affiliation_id`)
) COMMENT 'PRO affiliation (ASCAP/BMI/SESAC/PRS) for performance royalty routing.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`rights`.`neighbouring_rights_claim` (
