    `claim_period_end_date` DATE COMMENT '',
    `claim_period_start` DATE COMMENT 'Start of the usage period claimed.',
    `claim_period_start_date` DATE COMMENT '',
    `claim_reference` STRING COMMENT 'External claim reference number (SoundExchange-style).',
    `claim_share_pct` DECIMAL(18,2) COMMENT '',
    `claim_share_percent` DECIMAL(18,2) COMMENT '',
    `claim_status` STRING COMMENT 'Lifecycle status of the claim.',
    `claim_type` STRING COMMENT 'Performer / sound recording owner claim type.',
    `claimant_name` STRING COMMENT '',
    `claimant_role` STRING COMMENT '',
    `claimed_amount` DECIMAL(18,2) COMMENT 'Monetary amount claimed.',
    `collecting_society` STRING COMMENT 'Collecting society / PRO (e.g. SoundExchange).',
    `collection_agency` STRING COMMENT '',
    `collection_society` STRING COMMENT 'Collecting body (e.g. SoundExchange, PPL).',
    `created_at` TIMESTAMP COMMENT 'Record creation timestamp.',
    `created_by_user` STRING COMMENT '',
    `created_timestamp` TIMESTAMP COMMENT '',
    `currency_code` STRING COMMENT 'ISO currency code of the claimed amount.',
    `is_disputed_flag` BOOLEAN COMMENT '',
    `is_non_interactive_flag` BOOLEAN COMMENT 'True for non-interactive digital transmissions.',
    `isrc` STRING COMMENT 'ISRC of the claimed recording.',
    `isrc_code` STRING COMMENT '',
    `master_owner_share_percent` DECIMAL(18,2) COMMENT 'Percentage share attributable to the master rights owner.',
    `master_recording_isrc` STRING COMMENT 'ISRC of the master recording the claim covers.',
    `non_interactive_flag` BOOLEAN COMMENT 'True when usage is non-interactive digital transmission (statutory license).',
    `ownership_share_percent` DECIMAL(18,2) COMMENT 'Ownership share percentage for the claim.',
    `paid_amount` DECIMAL(18,2) COMMENT '',
    `performance_period_end_date` DATE COMMENT 'End of digital performance reporting period.',
    `performance_period_start_date` DATE COMMENT 'Start of digital performance reporting period.',
    `performance_share_percent` DECIMAL(18,2) COMMENT 'Performer share percentage.',
    `performer_role` STRING COMMENT '',
    `performer_share_percent` DECIMAL(18,2) COMMENT 'Percentage share attributable to the performer.',
    `period_end_date` DATE COMMENT 'Performance period end.',
    `period_start_date` DATE COMMENT 'Performance period start.',
    `play_count` BIGINT COMMENT 'Number of non-interactive digital plays.',
    `reporting_period_end_date` DATE COMMENT 'End of the usage reporting period.',
    `reporting_period_start_date` DATE COMMENT 'Start of the usage reporting period.',
    `service_type` STRING COMMENT 'Non-interactive digital service type (webcast, satellite_radio, cable_radio).',
    `source_code` STRING COMMENT 'Natural id in the source system.',
    `submitted_at` TIMESTAMP COMMENT 'Timestamp the claim was submitted to the collection society.',
    `submitted_date` DATE COMMENT 'Date the claim was submitted.',
    `territory` STRING COMMENT 'Territory in which the digital plays occurred.',
    `updated_at` TIMESTAMP COMMENT 'Record update timestamp.',
    `updated_by_user` STRING COMMENT '',
    `updated_timestamp` TIMESTAMP COMMENT '',
    `usage_period_end` DATE COMMENT 'End of the usage/reporting period.',
    `usage_period_end_date` DATE COMMENT '',
    `usage_period_start` DATE COMMENT 'Start of the usage/reporting period.',
    `usage_period_start_date` DATE COMMENT '',
    `usage_play_count` BIGINT COMMENT 'Number of reported non-interactive plays in the period.',
    CONSTRAINT pk_neighbouring_rights_claim PRIMARY KEY(`neighbouring_rights_claim_id`)
) COMMENT 'SoundExchange-style non-interactive digital neighbouring rights claim';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`rights`.`mechanical_royalty_report` (
    `mechanical_royalty_report_id` BIGINT COMMENT 'Surrogate primary key.',
    `composition_id` BIGINT COMMENT '',
    `license_agreement_id` BIGINT COMMENT 'Underlying mechanical license agreement.',
    `master_recording_id` BIGINT COMMENT 'FK to the master recording (ISRC-bearing) the usage relates to.',
