    `created_at` TIMESTAMP COMMENT 'Record creation timestamp.',
    `created_by_user` STRING COMMENT '',
    `created_timestamp` TIMESTAMP COMMENT '',
    `currency_code` STRING COMMENT 'Currency of amounts.',
    `download_count` BIGINT COMMENT 'Number of permanent downloads reported.',
    `dsp_name` STRING COMMENT '',
    `gross_royalty_amount` DECIMAL(18,2) COMMENT 'Gross mechanical royalty amount.',
    `interactive_stream_count` BIGINT COMMENT 'Number of interactive streams reported.',
    `is_matched_flag` BOOLEAN COMMENT 'True if usage has been matched to the composition.',
    `is_mma_compliant_flag` BOOLEAN COMMENT 'Whether the report complies with the Music Modernization Act.',
    `isrc` STRING COMMENT 'ISRC of the master recording.',
    `isrc_code` STRING COMMENT 'ISRC of the embodying recording.',
    `issued_date` DATE COMMENT 'Date the report was issued.',
    `iswc` STRING COMMENT '',
    `iswc_code` STRING COMMENT '',
    `limited_download_count` BIGINT COMMENT 'Count of limited downloads in the reporting period.',
    `matched_flag` BOOLEAN COMMENT '',
    `mechanical_rate` DECIMAL(18,2) COMMENT '',
    `mechanical_royalty_amount` DECIMAL(18,2) COMMENT 'Mechanical royalty amount due under MMA flows.',
    `mechanical_royalty_rate` DECIMAL(18,2) COMMENT 'Statutory mechanical royalty rate.',
    `mlc_account_number` STRING COMMENT '',
    `mlc_match_status` STRING COMMENT 'MLC matching status of the composition.',
    `mlc_member_code` STRING COMMENT 'Mechanical Licensing Collective member identifier.',
    `mlc_work_code` STRING COMMENT 'Mechanical Licensing Collective canonical work identifier.',
    `net_royalty_amount` DECIMAL(18,2) COMMENT 'Net mechanical royalty amount payable.',
    `paid_flag` BOOLEAN COMMENT 'Whether the royalty has been paid.',
    `play_count` BIGINT COMMENT 'Number of reported uses/plays in the period.',
    `publisher_share_percent` DECIMAL(18,2) COMMENT 'Publisher ownership share percentage applied to the payout.',
    `report_period_end` DATE COMMENT 'End of the mechanical royalty reporting period.',
    `report_period_end_date` DATE COMMENT 'End of the mechanical royalty reporting period.',
    `report_period_start` DATE COMMENT 'Start of the mechanical royalty reporting period.',
    `report_period_start_date` DATE COMMENT 'Start of the mechanical royalty reporting period.',
    `report_reference` STRING COMMENT 'MLC report reference identifier.',
    `report_status` STRING COMMENT 'Lifecycle status of the report.',
    `report_submitted_date` DATE COMMENT '',
    `report_type` STRING COMMENT 'Report type (blanket_license, matched, unmatched).',
    `reporting_agency` STRING COMMENT 'Reporting body (e.g. MLC).',
    `reporting_period_end` DATE COMMENT 'End of the reporting period.',
    `reporting_period_end_date` DATE COMMENT '',
    `reporting_period_start` DATE COMMENT 'Start of the reporting period.',
    `reporting_period_start_date` DATE COMMENT '',
    `royalty_amount` DECIMAL(18,2) COMMENT '',
    `royalty_currency` STRING COMMENT '',
    `royalty_rate` DECIMAL(18,2) COMMENT 'Applicable statutory mechanical royalty rate.',
    `source_code` STRING COMMENT 'Natural id in the source system.',
    `statutory_rate` DECIMAL(18,2) COMMENT 'Applicable statutory mechanical rate.',
    `stream_count` BIGINT COMMENT '',
    `submission_date` DATE COMMENT 'Date the report was submitted to the MLC.',
    `submitted_at` TIMESTAMP COMMENT 'Timestamp the report was submitted.',
    `submitted_date` DATE COMMENT 'Date the report was submitted.',
    `units_reported` BIGINT COMMENT 'Number of mechanical units reported.',
    `unmatched_flag` BOOLEAN COMMENT 'Whether the report covers unmatched works (black box).',
    `updated_at` TIMESTAMP COMMENT 'Record update timestamp.',
    `updated_by_user` STRING COMMENT '',
    `updated_timestamp` TIMESTAMP COMMENT '',
    `usage_count` BIGINT COMMENT 'Number of reported uses / streams.',
    CONSTRAINT pk_mechanical_royalty_report PRIMARY KEY(`mechanical_royalty_report_id`)
) COMMENT 'MLC mechanical royalty report under the US Music Modernization Act';

